extension UIViewController {
    func trackScreenView() {
        let screenName = String(describing: type(of: self))
        AnalyticsManager.shared.trackScreenView(screenName: screenName)
    }
}

extension URLSession {
    static func logDataTask(request: URLRequest, response: URLResponse?, data: Data?, error: Error?) {
        guard let url = request.url?.absoluteString,
              let method = request.httpMethod else { return }
        
        let requestPayload = request.httpBody != nil ? String(data: request.httpBody!, encoding: .utf8) ?? "nil" : "nil"
        let responsePayload = data != nil ? String(data: data!, encoding: .utf8) ?? "nil" : "nil"
        let statusCode = (response as? HTTPURLResponse)?.statusCode ?? 0
        
        AnalyticsLogger.shared.logAPICall(url: url, method: method, requestPayload: requestPayload, responsePayload: responsePayload, statusCode: statusCode)
        
        if let error = error {
            AnalyticsLogger.shared.logError(error: error, userId: nil, additionalInfo: "API Error")
        }
    }
}

extension UIApplication {
    static func logAppLifecycleEvent(_ event: String) {
        let logMessage = "App Lifecycle - Event: \(event)"
        NSLog("[Analytics] %@", logMessage)
        print("[Analytics] \(logMessage)")
    }
}

